    const nStr = String(n);
    const rStr = nStr.split('').reverse().join('');
    const r = parseInt(rStr);

    // 2. Determine the range [L, R]
    const L = Math.min(n, r);
    const R = Math.max(n, r);

    // 3. Calculate the sum of primes in the range [L, R]
    let sum = 0;
